     AcceptB(pkA, pkB, t, r, k) @ #i & HonestA(pkA) @ #h
     ==>
       (Ex #j. RunningA(pkA, pkB, t, r, k) @ #j & #j < #i)
       | (Ex #ra. LtkRevealA(pkA) @ #ra & #ra < #i)
       | (Ex pkC #rca. LtkRevealCA(pkC) @ #rca & #rca < #i)
  "

end
